mapper.select:
select Course_ID as courseId, Course_Name as courseName, Course_Type as courseType, Course_StartWeek as courseStartWeek, Course_EndWeek as courseEndWeek, Course_SingleHour as courseSingleHour, COALESCE(NULLIF(Required_Classroom_Type, ''), '普通教室') as requiredClassroomType from course
and Course_Name like concat('%', #{courseName}, '%')
and Course_Type = #{courseType}
order by Course_ID limit #{offset}, #{pageSize}

select count(*) from course
and Course_Name like concat('%', #{courseName}, '%')
and Course_Type = #{courseType}
